#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <cstdint>
#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T>
void conv1d_kernel(const T * __restrict__ in,
                   T * __restrict__ out,
                   const T * __restrict__ mask,
                   const int input_width,
                   const int mask_width,
                   const int bs)
{
  int grids = input_width / bs;
  #pragma omp target teams distribute parallel for num_teams(grids) thread_limit(bs) \
          is_device_ptr(in, out, mask)
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += in[start + j] * mask[j];
      }
    }
    out[i] = s;
  }
}

template<typename T>
void conv1d_tiled_kernel(const T * __restrict__ in,
                         T * __restrict__ out,
                         const T * __restrict__ mask,
                         const int input_width,
                         const int mask_width,
                         const int bs)
{
  int grids = input_width / bs;
  #pragma omp target teams num_teams(grids) thread_limit(bs) is_device_ptr(in, out, mask)
  {
    T tile[MAX_BLOCK_SIZE + MAX_MASK_WIDTH - 1];
    int b = omp_get_team_num();
    int base = b * bs;
    int n = mask_width / 2;

    #pragma omp parallel num_threads(bs)
    {
      int tx = omp_get_thread_num();
      if (tx < bs) {
        int halo_left = (b - 1) * bs + tx;
        if (tx >= bs - n) {
          tile[tx - (bs - n)] = (halo_left < 0) ? (T)0 : in[halo_left];
        }

        tile[n + tx] = in[base + tx];

        int halo_right = (b + 1) * bs + tx;
        if (tx < n) {
          tile[tx + bs + n] = (halo_right >= input_width) ? (T)0 : in[halo_right];
        }

        #pragma omp barrier

        T s = 0;
        for (int j = 0; j < mask_width; j++) {
          s += tile[tx + j] * mask[j];
        }
        out[base + tx] = s;
      }
    }
  }
}

template<typename T>
void conv1d_tiled_caching_kernel(const T * __restrict__ in,
                                 T * __restrict__ out,
                                 const T * __restrict__ mask,
                                 const int input_width,
                                 const int mask_width,
                                 const int bs)
{
  int grids = input_width / bs;
  #pragma omp target teams num_teams(grids) thread_limit(bs) is_device_ptr(in, out, mask)
  {
    T tile[MAX_BLOCK_SIZE];
    int b = omp_get_team_num();
    int base = b * bs;

    #pragma omp parallel num_threads(bs)
    {
      int tx = omp_get_thread_num();
      if (tx < bs) {
        int i = base + tx;
        tile[tx] = in[i];

        #pragma omp barrier

        int this_tile_start = base;
        int next_tile_start = (b + 1) * bs;
        int start = i - (mask_width / 2);

        T s = 0;
        for (int j = 0; j < mask_width; j++) {
          int in_index = start + j;
          if (in_index >= 0 && in_index < input_width) {
            if (in_index >= this_tile_start && in_index < next_tile_start) {
              s += tile[tx + j - (mask_width / 2)] * mask[j];
            } else {
              s += in[in_index] * mask[j];
            }
          }
        }
        out[i] = s;
      }
    }
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs((double)s - (double)d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes);
  b = (T *)malloc(size_bytes);

  T h_mask[MAX_MASK_WIDTH];

  for (int i = 0; i < MAX_MASK_WIDTH; i++) h_mask[i] = 1;

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = rand() % 256;
  }

  #pragma omp target data map(to: a[0:input_width], h_mask[0:MAX_MASK_WIDTH]) map(from: b[0:input_width])
  {
    T *d_a = a;
    T *d_b = b;
    T *d_mask = h_mask;

    #pragma omp target data use_device_ptr(d_a, d_b, d_mask)
    {
      for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
        auto start = std::chrono::steady_clock::now();
        for (int i = 0; i < repeat; i++) {
          conv1d_kernel<T>(d_a, d_b, d_mask, input_width, mask_width, bs);
        }
        auto end = std::chrono::steady_clock::now();
        auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
        printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
               bs, (time * 1e-3f) / repeat);
        #pragma omp target update from(b[0:input_width])
        reference(a, b, h_mask, input_width, mask_width);
      }

      for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
        auto start = std::chrono::steady_clock::now();
        for (int i = 0; i < repeat; i++) {
          conv1d_tiled_kernel<T>(d_a, d_b, d_mask, input_width, mask_width, bs);
        }
        auto end = std::chrono::steady_clock::now();
        auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
        printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
               bs, (time * 1e-3f) / repeat);
        #pragma omp target update from(b[0:input_width])
        reference(a, b, h_mask, input_width, mask_width);
      }

      for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
        auto start = std::chrono::steady_clock::now();
        for (int i = 0; i < repeat; i++) {
          conv1d_tiled_caching_kernel<T>(d_a, d_b, d_mask, input_width, mask_width, bs);
        }
        auto end = std::chrono::steady_clock::now();
        auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
        printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
               bs, (time * 1e-3f) / repeat);
        #pragma omp target update from(b[0:input_width])
        reference(a, b, h_mask, input_width, mask_width);
      }
    }
  }

  free(a);
  free(b);
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);

  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width);

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}
